// Extract message data
const body = $json.body;
const data = body.data;
const key = data.key;

const remoteJid = key.remoteJid;
const messageId = key.id;
const fromMe = key.fromMe;
const source = data.source;
const timestamp = data.messageTimestamp;
const messageText = data.message.conversation || '';
const pushName = data.pushName || 'Unknown';

// CUSTOMER = inbound (fromMe false). Everything we/the human send is fromMe true
// and goes to the OUTBOUND path, where the server tells us (by matching the
// text we sent) whether it is our own echo or a real human message.
let messageType = 'OUTBOUND';
if (fromMe === false) {
  const msgType = data.messageType || '';
  const isMedia = msgType.includes('image') || msgType.includes('video') || msgType.includes('audio') || msgType.includes('document') || msgType.includes('sticker');

  if (remoteJid.includes('@g.us') || remoteJid.includes('@broadcast') || remoteJid.includes('-')) {
    messageType = 'GROUP';
  } else if (isMedia) {
    messageType = 'MEDIA_IGNORE';
  } else {
    messageType = 'CUSTOMER';
  }
}

return {
  remoteJid: remoteJid,
  messageId: messageId,
  fromMe: fromMe,
  source: source,
  timestamp: timestamp,
  messageText: messageText,
  pushName: pushName,
  messageType: messageType,
  isCustomer: messageType === 'CUSTOMER'
};

