// Strip the hidden completion token before sending, and report whether the
// AI signalled that it has finished qualifying this lead (all four answers).
const out = ($('AI Agent').item.json.output || '').toString();
const qualified = /<<\s*QUALIFIED\s*>>/i.test(out);
const cleanText = out.replace(/<<\s*QUALIFIED\s*>>/ig, '').trim();
return { cleanText: cleanText, qualified: qualified };
